def normalize_cmd(cmd: tuple[str, ...]) -> tuple[str, ...]:
    """
    विंडोज़ पर निम्नलिखित समस्याओं के समाधान:  
    - https://bugs.python.org/issue8557  
    - विंडोज़ शैबैंग (shebang) को पार्स नहीं करता है।  

    यह फ़ंक्शन गहरे पथ (deep-path) वाले शैबैंग को भी सही तरीके से काम करने में सक्षम बनाता है।  
    """
    if not cmd:
        return cmd

    # Normalize the command by handling shebang and deep paths
    normalized_cmd = []
    for part in cmd:
        if part.startswith('#!'):
            # Handle shebang
            normalized_cmd.append(part)
        else:
            # Normalize the path
            normalized_cmd.append(part.replace('\\', '/'))

    return tuple(normalized_cmd)

import time
from collections import OrderedDict
from functools import wraps

def ttl_cache(maxsize=128, ttl=600, timer=time.monotonic, typed=False):
    """
    एक डेकोरेटर जो एक फ़ंक्शन को एक मेमोराइज़िंग कॉलेबल के साथ रैप करता है,
    जो `maxsize` तक के परिणामों को सेव करता है। यह एक Least Recently Used (LRU)
    एल्गोरिदम पर आधारित होता है और प्रत्येक आइटम के लिए एक समय-सीमा (Time-To-Live, TTL) 
    मान लागू करता है।
    """
    def decorator(func):
        cache = OrderedDict()
        timestamps = {}

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = args if not typed else (type(arg) for arg in args)
            if key in cache:
                if timer() - timestamps[key] < ttl:
                    return cache[key]
                else:
                    del cache[key]
                    del timestamps[key]
            result = func(*args, **kwargs)
            cache[key] = result
            timestamps[key] = timer()
            if len(cache) > maxsize:
                cache.popitem(last=False)
            return result

        return wrapper

    return decorator

def minimalBases(classes):
    """
    आधार कक्षाओं (base classes) की सूची को उसके क्रमबद्ध न्यूनतम समकक्ष (ordered minimum equivalent) में घटाएं।
    """
    from collections import defaultdict

    def find_parent(class_name):
        if class_name not in parent:
            return class_name
        root = find_parent(parent[class_name])
        parent[class_name] = root  # Path compression
        return root

    parent = {}
    for cls in classes:
        for base in cls.__bases__:
            parent[base.__name__] = cls.__name__

    unique_bases = set()
    for cls in classes:
        root = find_parent(cls.__name__)
        unique_bases.add(root)

    return list(unique_bases)

