def difference(d1, d2, level=-1):
    def recursive_difference(d1, d2, level):
        if level == 0:
            return {}
        result = {}
        for key in d1:
            if key not in d2:
                result[key] = d1[key]
            else:
                if isinstance(d1[key], dict) and isinstance(d2[key], dict):
                    nested_diff = recursive_difference(d1[key], d2[key], level - 1)
                    if nested_diff:
                        result[key] = nested_diff
                elif d1[key] != d2[key]:
                    result[key] = d1[key]
        return result

    return recursive_difference(d1, d2, level)

import re

class ValidationError(Exception):
    def __init__(self, messages):
        self.messages = messages

def _validate_labels(labels):
    regex_key = r'^[a-zA-Z_][a-zA-Z0-9_]*$'  # Example regex for valid keys
    regex_value = r'^[a-zA-Z0-9]+$'  # Example regex for valid values
    errors = []

    for key, value in labels.items():
        if not isinstance(key, str) or not re.match(regex_key, key):
            errors.append({key: f"Label key '{key}' does not match the regex [{regex_key}]"})

        if isinstance(value, list):
            for item in value:
                if not isinstance(item, str) or not re.match(regex_value, item):
                    errors.append({str(value): 'expected string or bytes-like object'})
        elif not isinstance(value, str) or not re.match(regex_value, value):
            errors.append({str(value): 'expected string or bytes-like object'})

    if errors:
        raise ValidationError(errors)

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    यह फ़ंक्शन :func:``generate_default_observer_schema_list`` के साथ मिलकर पुनरावृत्त रूप से (recursively) कॉल किया जाता है ताकि किसी Kubernetes संसाधन (resource) के एक भाग से डिफ़ॉल्ट ``observer_schema`` का हिस्सा उत्पन्न किया जा सके, जिसे क्रमशः ``manifest_dict`` या ``manifest_list`` द्वारा परिभाषित किया गया है।

    आर्ग्युमेंट्स (Args):
    - manifest_dict (dict): आंशिक Kubernetes संसाधन (Partial Kubernetes resources)।
    - first_level (bool, optional): यदि True है, तो यह इंगित करता है कि डिक्शनरी Kubernetes संसाधन के पूरे observer schema का प्रतिनिधित्व करती है।

    रिटर्न्स (Returns):
    - dict: उत्पन्न आंशिक observer_schema (Generated partial observer_schema)।

    यह फ़ंक्शन ``manifest_dict`` से एक नई डिक्शनरी बनाता है और सभी non-list और non-dict मानों को ``None`` से बदल देता है।

    यदि यह ``first_level`` डिक्शनरी है (यानी किसी संसाधन के लिए पूरा ``observer_schema``), तो पहचानने वाले फ़ील्ड्स (identifying fields) के मान ``manifest`` फ़ाइल से कॉपी किए जाते हैं।
    """
    observer_schema = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value, False)
        elif isinstance(value, list):
            observer_schema[key] = [generate_default_observer_schema_dict(item, False) if isinstance(item, dict) else None for item in value]
        else:
            observer_schema[key] = None

    if first_level:
        # Assuming 'name' and 'namespace' are identifying fields
        if 'name' in manifest_dict:
            observer_schema['name'] = manifest_dict['name']
        if 'namespace' in manifest_dict:
            observer_schema['namespace'] = manifest_dict['namespace']

    return observer_schema

def generate_default_observer_schema(app):
    """
    प्रत्येक Kubernetes संसाधन के लिए डिफ़ॉल्ट ऑब्ज़र्वर स्कीमा उत्पन्न करें जो ``spec.manifest`` में मौजूद है और जिसके लिए कोई कस्टम ऑब्ज़र्वर स्कीमा निर्दिष्ट नहीं किया गया है।

    आर्ग्युमेंट्स:
        app (krake.data.kubernetes.Application): वह एप्लिकेशन जिसके लिए डिफ़ॉल्ट ऑब्ज़र्वर स्कीमा उत्पन्न करना है।
    """
    default_schema = {}
    for resource in app.spec.manifest:
        if 'custom_observer_schema' not in resource:
            default_schema[resource['kind']] = {
                'apiVersion': resource['apiVersion'],
                'metadata': {
                    'name': resource['metadata']['name'],
                    'namespace': resource['metadata'].get('namespace', 'default')
                },
                'spec': resource.get('spec', {})
            }
    return default_schema

def formatmany(
                self,
                sql: AnyStr,
                many_params: Union[Iterable[Dict[Union[str, int], Any]], Iterable[Sequence[Any]]],
        ) -> Tuple[AnyStr, Union[List[Dict[Union[str, int], Any]], List[Sequence[Any]]]]:
    # Initialize the formatted SQL and the output parameters list
    formatted_sql = sql
    out_params = []

    # Process each set of parameters
    for params in many_params:
        if isinstance(params, dict):
            # If params is a dictionary, convert to out-style
            out_params.append(params)
            for key, value in params.items():
                formatted_sql = formatted_sql.replace(f":{key}", self._format_value(value))
        elif isinstance(params, (list, tuple)):
            # If params is a list or tuple, convert to out-style
            out_params.append(params)
            for index, value in enumerate(params):
                formatted_sql = formatted_sql.replace(f"${index + 1}", self._format_value(value))

    return formatted_sql, out_params

def _format_value(self, value: Any) -> str:
    # Convert the value to a string representation for SQL
    if isinstance(value, str):
        return f"'{value}'"
    elif value is None:
        return "NULL"
    else:
        return str(value)

def status_str(self, prefix=''):
    """
    सत्यापन लॉग (validation log) का स्ट्रिंग प्रतिनिधित्व लौटाएं, वैकल्पिक प्रीफिक्स के साथ।
    """
    log_representation = f"{prefix}Validation Log:\n"
    for entry in self.validation_log:
        log_representation += f"{prefix} - {entry}\n"
    return log_representation.strip()

def validate(self, inventory, extract_spec_version=False):
    """
    दिए गए इन्वेंटरी को सत्यापित करें।

    यदि `extract_spec_version` का मान `True` है, तो यह `type` मान को देखकर 
    स्पेसिफिकेशन वर्जन निर्धारित करेगा। यदि `type` मान मौजूद नहीं है या यह 
    मान्य नहीं है, तो अन्य परीक्षण `self.spec_version` में दिए गए वर्जन के 
    आधार पर किए जाएंगे।
    """
    if extract_spec_version:
        if 'type' in inventory:
            spec_version = inventory['type']
            # Validate spec_version against known types
            if spec_version not in self.valid_types:
                raise ValueError(f"Invalid type: {spec_version}")
        else:
            spec_version = self.spec_version
    else:
        spec_version = self.spec_version

    # Perform additional validation based on spec_version
    if spec_version == 'v1':
        # Perform v1 specific validation
        self.validate_v1(inventory)
    elif spec_version == 'v2':
        # Perform v2 specific validation
        self.validate_v2(inventory)
    else:
        raise ValueError(f"Unknown spec version: {spec_version}")

