def check_digests_present_and_used(self, manifest_files, digests_used):
    """
    मैनिफेस्ट में सभी आवश्यक डाइजेस्ट्स की जांच करें कि वे मौजूद हैं और उपयोग हो रहे हैं।
    """
    missing_digests = []
    used_digests = set(digests_used)

    for manifest in manifest_files:
        for digest in manifest.get('digests', []):
            if digest in used_digests:
                used_digests.remove(digest)

    missing_digests = list(used_digests)

    return missing_digests

def get_logical_path_map(inventory, version):
    """
    इन्वेंटरी में दिए गए संस्करण (version) के लिए स्थिति (state) में लॉजिकल पथों और डिस्क पर फ़ाइलों के बीच का मैप प्राप्त करें।

    रिटर्न करता है एक डिक्शनरी: 
    `logical_path_in_state -> set(content_files)`

    `content_files` का सेट उन डुप्लिकेट फ़ाइलों के संदर्भ भी शामिल कर सकता है जो उस संस्करण के बाद के संस्करणों में मौजूद हैं जिसे वर्णित किया जा रहा है।
    """
    logical_path_map = {}

    for item in inventory:
        if item['version'] == version:
            logical_path = item['logical_path']
            content_files = set(item['content_files'])
            logical_path_map[logical_path] = logical_path_map.get(logical_path, set()).union(content_files)

    # Include duplicates from later versions
    for item in inventory:
        if item['version'] > version:
            logical_path = item['logical_path']
            if logical_path in logical_path_map:
                logical_path_map[logical_path].update(item['content_files'])

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    इन्वेंटरी में फिक्सिटी ब्लॉक को सत्यापित करें।
    फिक्सिटी ब्लॉक की संरचना की जांच करें और सुनिश्चित करें कि केवल वे फाइलें
    जो मैनिफेस्ट में सूचीबद्ध हैं, वही संदर्भित की गई हैं।
    """
    # Check if fixity is a dictionary
    if not isinstance(fixity, dict):
        raise ValueError("Fixity must be a dictionary.")

    # Check if all files in fixity are in manifest_files
    for file in fixity.keys():
        if file not in manifest_files:
            raise ValueError(f"File {file} in fixity is not listed in manifest files.")

    # Check the structure of the fixity block
    for file, checksum in fixity.items():
        if not isinstance(checksum, str):
            raise ValueError(f"Checksum for file {file} must be a string.")
        if len(checksum) == 0:
            raise ValueError(f"Checksum for file {file} cannot be empty.")

    return True

def add_rendition(self, lang, file_path):
    """
    Adds a rendition of a file in a specified language.

    Args:
        lang (str): The language code for the rendition (e.g., 'en').
        file_path (str): The path to the rendition file.

    Example:
        {
            "original": "artigo02.pdf",
            "en": "artigo02-en.pdf",
        }
    """
    if not hasattr(self, 'renditions'):
        self.renditions = {}

    self.renditions[lang] = file_path

def fix_namespace_prefix_w(content):
    """
    ऐसा कोड लिखें जो उस टेक्स्ट को परिवर्तित करे जो डिफ़ॉल्ट रूप से 'w:st="' है, उसे 'w-st="' में बदल दे।
    """
    return content.replace('w:st="', 'w-st="')

def match_pubdate(node, pubdate_xpaths):
    """
    `pubdate_xpaths` सूची में पहला मेलित मान (match) लौटाता है।
    """
    for xpath in pubdate_xpaths:
        result = node.xpath(xpath)
        if result:
            return result[0]
    return None

def _fromutc(self, dt):
    """
    यह वह स्थिति है जब हमें *पक्का* पता होता है कि हमारे पास एक अस्पष्टता रहित (unambiguous) डेटटाइम ऑब्जेक्ट है। इस मौके का उपयोग करते हुए, हम यह निर्धारित करते हैं कि क्या यह डेटटाइम अस्पष्ट (ambiguous) है और "फोल्ड" स्थिति में है (उदाहरण के लिए, यदि यह अस्पष्ट डेटटाइम का पहला कालानुक्रमिक (chronological) उदाहरण है)।

    पैरामीटर:
    - `dt`:  
      एक टाइमज़ोन-अवेयर :class:`datetime.datetime` ऑब्जेक्ट।
    """
    if dt.tzinfo is None:
        raise ValueError("dt must be timezone-aware")

    # Check if the datetime is ambiguous
    if dt.dst() is not None and dt.dst() != timedelta(0):
        # If the datetime has a non-zero DST offset, it is ambiguous
        raise ValueError("Ambiguous datetime")

    # Determine if the datetime is in the fold
    if dt < self.utcoffset() + self.dst():
        return dt - self.utcoffset()
    else:
        return dt - self.utcoffset() - self.dst()

def tzname_in_python2(namefunc):
    """
    Python 2 में यूनिकोड आउटपुट को बाइटस्ट्रिंग्स में बदलें।

    tzname() API ने Python 3 में बदलाव किया। पहले यह बाइट्स लौटाता था, 
    लेकिन इसे यूनिकोड स्ट्रिंग्स में बदल दिया गया।
    """
    def wrapper(*args, **kwargs):
        return namefunc(*args, **kwargs).encode('utf-8')
    return wrapper

def get_versions():
    """
    संस्करण जानकारी प्राप्त करें या यदि ऐसा करने में असमर्थ हैं तो डिफ़ॉल्ट मान लौटाएं।
    """
    try:
        import pkg_resources
        versions = {pkg.project_name: pkg.version for pkg in pkg_resources.working_set}
        return versions
    except Exception:
        return {"default": "unknown"}

def render(pieces, style):
    """
    दिए गए संस्करण टुकड़ों को निर्दिष्ट शैली में प्रस्तुत करें।
    """
    styled_pieces = []
    for piece in pieces:
        styled_piece = f"{style}: {piece}"
        styled_pieces.append(styled_piece)
    return "\n".join(styled_pieces)

def get_config():
    """
    # VersioneerConfig() ऑब्जेक्ट बनाएं, इसे डेटा से भरें और इसे लौटाएं।
